text.regex:
(?isx)
^
# The applicable basic warranty term is active; the expired-term path is rejected.
(?=.*(?:basic\s+vehicle\s+)?(?:warranty|coverage)[^.!?\n]{0,140}
    (?:active|in\s+effect|still\s+valid|within\s+(?:the\s+)?(?:term|period)|not\s+expired))

# The current damage is causally linked to an aftermarket / non-Tesla modification.
(?=.*(?:
      (?:aftermarket|non[\s_-]*tesla|third[\s_-]*party|modification|alteration)
      [^.!?\n]{0,180}
      (?:caus(?:e|ed|al)|result(?:ed)?|attribut(?:e|ed|able)|linked)
      [^.!?\n]{0,180}
      (?:damage|failure|issue|steering|assembly|component)
    |
      (?:damage|failure|issue|steering|assembly|component)
      [^.!?\n]{0,180}
      (?:caus(?:e|ed|al)|result(?:ed)?|attribut(?:e|ed|able)|linked)
      [^.!?\n]{0,180}
      (?:aftermarket|non[\s_-]*tesla|third[\s_-]*party|modification|alteration)
    ))

# Do not accept an unresolved "may/might/could be excluded" conclusion.
(?!.*(?:may|might|could|possibly|potentially)[^.!?\n]{0,90}
    (?:excluded|not\s+covered|outside\s+(?:ordinary\s+)?warranty))

# The modification-caused damage is definitively outside ordinary warranty coverage.
(?=.*(?:
      (?:ordinary|basic|vehicle)?\s*(?:warranty|coverage)
      [^.!?\n]{0,180}
      (?:does\s+not\s+cover|doesn['’]?t\s+cover|not\s+covered|excluded|outside\s+coverage|customer[\s_-]*pay)
    |
      (?:damage|repair|assembly|component)
      [^.!?\n]{0,180}
      (?:excluded|not\s+covered|outside\s+(?:ordinary\s+)?warranty|customer[\s_-]*pay)
    ))

# The exact vehicle is in scope and the campaign remedy is still open.
(?=.*(?:
      (?:your\s+)?(?:vin|vehicle|car)
      [^.!?\n]{0,180}
      (?:campaign|recall)
      [^.!?\n]{0,180}
      (?:in\s+scope|match(?:es|ed)?|included|appl(?:y|ies|icable))
    |
      (?:your\s+)?(?:vin|vehicle|car)
      [^.!?\n]{0,180}
      (?:in\s+scope|match(?:es|ed)?|included|appl(?:y|ies|icable))
      [^.!?\n]{0,180}
      (?:campaign|recall)
    |
      (?:campaign|recall)
      [^.!?\n]{0,180}
      (?:appl(?:y|ies|icable)|covers?|includes?|match(?:es|ed)?)
      [^.!?\n]{0,120}
      (?:your\s+)?(?:vin|vehicle|car)
    ))
(?=.*(?:campaign|recall|remedy)[^.!?\n]{0,160}
    (?:open|outstanding|not\s+(?:yet\s+)?completed|unremedied|still\s+available))

# The campaign remains a separate / independent official path despite the warranty exclusion.
(?=.*(?:
      (?:separate|separately|independent|independently|despite|regardless)
      [^.!?\n]{0,180}
      (?:campaign|recall|remedy)
    |
      (?:campaign|recall|remedy)
      [^.!?\n]{0,180}
      (?:separate|independent|still\s+appl(?:y|ies|icable)|remains?\s+appl(?:y|ies|icable)|does\s+not\s+disappear)
    ))

# Give the correct next step without claiming an action was already executed.
(?=.*(?:
      (?:schedule|arrange|contact|book|bring|take)
      [^.!?\n]{0,160}
      (?:tesla|service|campaign|recall|remedy)
    |
      (?:tesla|service\s+center)
      [^.!?\n]{0,160}
      (?:perform|complete|schedule|arrange)
      [^.!?\n]{0,100}
      (?:campaign|recall|remedy)
    ))
.*
$
